  flex: 1;
  height: 1.5px;
  background: linear-gradient(to right, #C8A96E, transparent);
}
.qibar-section-hd .sec-tag {
  font-size: 0.78rem;
  color: #7A7068;
  letter-spacing: 0.05em;
  text-transform: uppercase;
  white-space: nowrap;
}

