  display: block;
}
.topic-name {
  font-size: 0.88rem;
  font-weight: 600;
  color: #1A3A5C;
  margin: 0 0 3px;
}
.topic-desc {
  font-size: 0.78rem;
  color: #7A7068;
  margin: 0;
  line-height: 1.5;
}

